patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 934156f04f7f..8d6840aa592c 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -2773,6 +2773,7 @@ static Instruction *foldGEPOfPhi(GetElementPtrInst &GEP, PHINode *PN,
   auto *Op1 = dyn_cast<GetElementPtrInst>(PN->getOperand(0));
   if (!Op1)
     return nullptr;
+  GEPNoWrapFlags Flags = Op1->getNoWrapFlags();

   // Don't fold a GEP into itself through a PHI node. This can only happen
   // through the back-edge of a loop. Folding a GEP into itself means that
@@ -2790,6 +2791,7 @@ static Instruction *foldGEPOfPhi(GetElementPtrInst &GEP, PHINode *PN,
     if (!Op2 || Op1->getNumOperands() != Op2->getNumOperands() ||
         Op1->getSourceElementType() != Op2->getSourceElementType())
       return nullptr;
+    Flags &= Op2->getNoWrapFlags();

     // As for Op1 above, don't try to fold a GEP into itself.
     if (Op2 == &GEP)
@@ -2847,6 +2849,7 @@ static Instruction *foldGEPOfPhi(GetElementPtrInst &GEP, PHINode *PN,
     return nullptr;

   auto *NewGEP = cast<GetElementPtrInst>(Op1->clone());
+  NewGEP->setNoWrapFlags(Flags);
   if (DI == -1) {
     // All the GEPs feeding the PHI are identical. Clone one down into our
     // BB so that it can be merged with the current GEP.

